  ('optician-moex-01563', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者為正視眼，檢查結果調節力為4.0D。戴上單焦老花眼鏡時的清晰視力範圍（range）約為19公分至 80公分，在不考慮焦深（depthoffocus）的狀態下，該副眼鏡的度數為下列何者？', '["+1.25DS", "+2.50DS", "+4.00DS", "+5.25DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "8b6dc393482c", "answer_pdf_sha1": "838173d2fb56", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1507", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
